export const DEFAULT_COUNTRY_CODE = 'PE';

export function getCountryByCode(code: string): CountryEntry | undefined {
  return COUNTRIES.find((c) => c.code === code);
}

export function getCountryLevelLabels(code: string): CountryLevelLabels {
  return COUNTRY_LEVEL_LABELS[code] || COUNTRY_LEVEL_LABELS.DEFAULT;
}

export function searchCountries(query: string, limit = 20): CountryEntry[] {
  const q = query.trim().toLowerCase();
  if (!q) return COUNTRIES.slice(0, limit);
  return COUNTRIES.filter(
    (c) =>
      c.name.toLowerCase().includes(q) ||
      c.nameEn.toLowerCase().includes(q) ||
      c.code.toLowerCase() === q,
  ).slice(0, limit);
}
